import{_ as n,j as t,o as g,v as i}from"./chunks/framework.gVsiwu-7.js";const s=JSON.parse('{"title":"Message là gì ?","description":"","frontmatter":{"footer":true,"title":"Message là gì ?","authors":["lethanh"],"date":"2024-04-15T00:00:00.000Z","image":"/assets/1.1Jqj7e7N.jpg","outline":"deep","draft":false,"group":"2. Message and event stream"},"headers":[{"level":2,"title":"Message là gì ?","slug":"message-la-gi-1","link":"#message-la-gi-1","children":[{"level":3,"title":"Tóm gọn Message là gì","slug":"tom-gon-message-la-gi","link":"#tom-gon-message-la-gi","children":[]}]},{"level":2,"title":"Đặc điểm của Message","slug":"đac-điem-cua-message","link":"#đac-điem-cua-message","children":[]},{"level":2,"title":"Ví dụ về Message","slug":"vi-du-ve-message","link":"#vi-du-ve-message","children":[{"level":3,"title":"Ví dụ 1","slug":"vi-du-1","link":"#vi-du-1","children":[]},{"level":3,"title":"Ví dụ 2","slug":"vi-du-2","link":"#vi-du-2","children":[]}]},{"level":2,"title":"Tổng kết","slug":"tong-ket","link":"#tong-ket","children":[]}],"relativePath":"study/thanhlv-study-2024/2024-04-15-message-la-gi.md","filePath":"study/thanhlv-study-2024/2024-04-15-message-la-gi.md","lastUpdated":1715527409000}'),h={name:"study/thanhlv-study-2024/2024-04-15-message-la-gi.md"},a=[i('<h1 id="message-la-gi" tabindex="-1">Message là gì ? <a class="header-anchor" href="#message-la-gi" aria-label="Permalink to &quot;Message là gì ?&quot;">​</a></h1><p>Mở đầu học về <code>Message and event stream</code> thì mình sẽ giải thích các kiến thức cơ bản trước. Kiến thức đầu tiên là hiểu về <strong>Message</strong>.</p><p><strong>Message</strong> không chỉ là một khái niệm đơn giản; nó là trung tâm của hệ thống, là phương tiện mà dữ liệu di chuyển thông qua giữa các thành phần trong hệ thống.</p><p><strong>Message</strong> không chỉ là một dòng văn bản hay một chuỗi dữ liệu vô nghĩa. Nó mang trên mình một giá trị, một ý nghĩa, và một mục đích. Và điều quan trọng là, nó là cầu nối kết nối giữa các thành phần trong hệ thống, tạo ra một luồng thông tin liên tục và không gián đoạn.</p><p>Hãy cùng mình khám phá sâu hơn về bản chất và ý nghĩa thực sự của Message, và cách nó đóng vai trò quan trọng trong việc xây dựng các hệ thống phân phối hiệu quả. Hãy bắt đầu cuộc hành trình này và khám phá cùng nhau!</p><nav class="table-of-contents"><ul><li><a href="#message-la-gi-1">Message là gì ?</a><ul><li><a href="#tom-gon-message-la-gi">Tóm gọn Message là gì</a></li></ul></li><li><a href="#đac-điem-cua-message">Đặc điểm của Message</a></li><li><a href="#vi-du-ve-message">Ví dụ về Message</a><ul><li><a href="#vi-du-1">Ví dụ 1</a></li><li><a href="#vi-du-2">Ví dụ 2</a></li></ul></li><li><a href="#tong-ket">Tổng kết</a></li></ul></nav><h2 id="message-la-gi-1" tabindex="-1">Message là gì ? <a class="header-anchor" href="#message-la-gi-1" aria-label="Permalink to &quot;Message là gì ?&quot;">​</a></h2><ul><li><p><strong>Đầu tiên</strong>, <strong>Message</strong> là một yêu cầu có chứa một lượng dữ liệu được gửi từ A đến B(Từ hệ thống A đến hệ thống B) và được B nhận và xử lý theo yêu cầu.</p></li><li><p><strong>Thứ hai</strong>, <strong>Message</strong> thường đi kèm với metadata, tức là các thông tin mô tả về Message. Metadata này có thể gồm nhiều thông tin, người gửi, thời gian gửi, người nhận...</p></li><li><p><strong>Thứ ba</strong>, Format của dữ liệu <strong>Message</strong> sẽ là một hợp đồng giữa A và B. hợp đồng này gồm nhiều thứ ví dụ: Định dạng tin nhắn(Json), thuật toán mã hóa, các dữ liệu require trong Json....</p><ul><li>Thông thường Format này sẽ được hệ thống nhận tin nhắn, tức B xác định. Tuy nhiên nhiều trường hợp có thể A xác định và B sẽ làm theo.</li></ul></li><li><p><strong>Thứ tư</strong>, <strong>Message</strong> được mang ý nghĩa giả định người gửi sẽ gửi dữ liệu và sẽ có một người nhận yêu cầu và xử lý yêu cầu. Nếu hành động không được thực hiện tức là đã bi phạm một <strong>business rule</strong> nào đó.</p><ul><li>Thông thường, đây là bước đầu tiên của một quá trình dẫn đến, A nhận được dữ liệu của B(HTML), B thay đổi dữ liệu.... <img src="/assets/1.1Jqj7e7N.jpg" alt="Image"></li></ul></li></ul><h3 id="tom-gon-message-la-gi" tabindex="-1"><strong>Tóm gọn Message là gì</strong> <a class="header-anchor" href="#tom-gon-message-la-gi" aria-label="Permalink to &quot;**Tóm gọn Message là gì**&quot;">​</a></h3><ul><li>Message là một yêu cầu thường chứa một khối lượng dữ liệu được chuyển từ một hệ thống sang hệ thống khác để thực hiện các hành động xử lý hoặc trao đổi thông tin.</li></ul><h2 id="đac-điem-cua-message" tabindex="-1">Đặc điểm của Message <a class="header-anchor" href="#đac-điem-cua-message" aria-label="Permalink to &quot;Đặc điểm của Message&quot;">​</a></h2><ul><li><p><strong>Đóng gói thông tin</strong>: Message chứ dữ liệu hoặc thông tin được đóng gói. Thông tin này có thể bảo gồm tin nhắn, câu lệnh, dữ liệu cần truyền đạt...</p></li><li><p><strong>Có cấu trúc</strong>: Message thường có một cấu trúc xác định, bảo gồm các metadata và nội dung(body). Metadata có thể chứa các thông tin về loại message, người gửi, người nhận và nhiều thuộc tính khác. Phần body chứa dữ liệu thực sự cần gửi đi.</p></li><li><p><strong>Đồng bộ hoặc không đồng bộ:</strong> :Message có thể được gửi một cách đồng bộ, người gửi sẽ chờ đợi phản hồi của người nhận trước khi tiếp tục, hoặc không đồng bộ nơi người gửi tiếp tục công việc mà không cần chờ phản hồi.</p></li><li><p><strong>Độc lập với giao thức</strong>: Message có thể được gửi qua nhiều giao thức khác nhau, HTTP, HTTPS, FTP, SMTP, MIME...</p></li><li><p><strong>Bảo mật</strong>: Message có thể được mã hóa và ký để đảm bảo tính bảo mật, toàn vẹn và xác thực nguồn gốc giúp bảo vệ khỏi sự nghe, nhìn lén và thay đổi hoặc giả mạo.</p></li><li><p><strong>Giao tiếp giữa các chệ thống</strong>: Message là phương tiện chính hiện tại sử dụng để giao tiếp giữa các hệ thống, dịch vụ và ứng dụng. Message cho phép chúng ta trao đổi dữ liệu linh hoạt và hiệu quả.</p></li><li><p><strong>Định hướng người nhận(Recipient Orientation)</strong>: Mỗi message được tạo ra sẽ gửi đi sẽ xác định đến 1 hoặc N người nhận message để đảm bảo rằng message đến đúng người hoặc hệ thống cần nó.</p></li></ul><h2 id="vi-du-ve-message" tabindex="-1">Ví dụ về Message <a class="header-anchor" href="#vi-du-ve-message" aria-label="Permalink to &quot;Ví dụ về Message&quot;">​</a></h2><h3 id="vi-du-1" tabindex="-1"><strong>Ví dụ 1</strong> <a class="header-anchor" href="#vi-du-1" aria-label="Permalink to &quot;**Ví dụ 1**&quot;">​</a></h3><p>Application <strong>A</strong> gửi Message đến Application <strong>B</strong> yêu cầu lấy về danh sách học sinh(Tin nhắn được gửi thông qua giao thức <strong>HTTP</strong>).</p><ul><li><ol><li><strong>A</strong> gửi <strong>Message</strong> đến B yều cầu lấy danh sách học sinh thông qua giao thức <strong>HTTP</strong></li></ol></li><li><ol start="2"><li><strong>B</strong> nhận được yêu cầu và kiểm tra đúng các định dạng format của <strong>HTTP</strong> và đúng <strong>business rule</strong>(User ở <strong>A</strong> có quyền đọc...)</li></ol><ul><li>Nếu <strong>A</strong> gửi sai format hoặc vi phạm business rule thì B sẽ từ chối yêu cầu.</li></ul></li><li><ol start="3"><li><strong>B</strong> sử lý yêu cầu và gửi trả lại phản hồi cho <strong>A</strong>.</li></ol></li></ul><h3 id="vi-du-2" tabindex="-1"><strong>Ví dụ 2</strong> <a class="header-anchor" href="#vi-du-2" aria-label="Permalink to &quot;**Ví dụ 2**&quot;">​</a></h3><p>Gửi thư từ nhà của <strong>A</strong> ở <strong>Hà Nội</strong> đến <strong>B</strong> ở <strong>Đà Nẵng</strong> yêu cầu vay 500k VND</p><ul><li><ol><li><strong>A</strong> thực hiện viết Message vào giấy để giở thư đến cho <strong>B</strong>.</li></ol></li><li><ol start="2"><li><strong>A</strong> sẽ sử dụng giao thức gửi thư qua bưu điện vì vậy cần sử dụng <strong>format bao thư</strong> kèm theo <strong>Metadata</strong> người gửi và người nhận.</li></ol></li><li><ol start="3"><li>Sau khi hoàn thành đầy đủ, giao thức bưu điện sẽ gửi thư đến <strong>B</strong> ở <strong>Đà Nẵng</strong>.</li></ol></li><li><ol start="4"><li>Sau khi B nhận thư, tiến hành đọc và xử lý các yêu cầu dựa trên <strong>business rule</strong>( Chơi thân không? Mình có 500k VND không ...)</li></ol></li><li><ol start="5"><li>Nếu thỏa mãn <strong>business rule</strong> B sẽ gửi Message lại đến B với 500K VND họặc không thỏa mãn sẽ gửi lại Message từ chối yêu cầu đến A thông qua giao thức bưu điện.</li></ol></li></ul><h2 id="tong-ket" tabindex="-1">Tổng kết <a class="header-anchor" href="#tong-ket" aria-label="Permalink to &quot;Tổng kết&quot;">​</a></h2><ul><li><p><strong>Message</strong> là một yêu cầu chứa dữ liệu được gửi từ hệ thống này sang hệ thống khác, có mục đích xử lý hoặc trao đổi thông tin.</p></li><li><p><strong>Không chỉ là dữ liệu</strong>, Message mang giá trị, ý nghĩa và mục đích, đóng vai trò là cầu nối giữa các thành phần trong hệ thống, tạo luồng thông tin liên tục.</p></li><li><p><strong>Metadata đi kèm với Message</strong> mô tả thông tin về người gửi, thời gian gửi, người nhận, giúp quản lý và xử lý Message hiệu quả.</p></li><li><p><strong>Format dữ liệu của Message</strong> thường được xác định bởi hợp đồng giữa hệ thống gửi và hệ thống nhận, thường là JSON, bao gồm cả thuật toán mã hóa và dữ liệu cần thiết.</p></li><li><p><strong>Mục đích</strong> của việc gửi Message là để truyền đạt thông tin hoặc yêu cầu thực hiện một công việc cụ thể giữa các thành phần trong hệ thống.</p></li></ul>',21)];const e=n(h,[["render",function(n,i,s,h,e,l){return g(),t("div",null,a)}]]);export{s as __pageData,e as default};
